    if grid[0][0] == 1 or grid[m-1][n-1] == 1:
        return -1
    queue = [(0, 0, 1)]
    visited = set((0, 0))
    while queue:
        x, y, dist = queue.pop(0)
        if (x, y) == (m-1, n-1):
            return dist
        for dx, dy in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
            nx, ny = x + dx, y + dy
            if 0 <= nx < m and 0 <= ny < n and grid[nx][ny] == 0 and (nx, ny) not in visited:
                queue.append((nx, ny, dist + 1))
                visited.add((nx, ny))
    return -1

